const isMissing = (v) => {
  if (v === null || v === undefined) return true;
  const s = String(v).trim().toLowerCase();
  return s === '' || s === 'null';
};
const clean = (v) => (isMissing(v) ? '' : v);

const fileName = $('Loop Over Items').first().json.fileName || 'Unknown document';

const sd = $getWorkflowStaticData('global');
if (!Array.isArray(sd.flags)) sd.flags = [];

const rows = [];

for (const item of $input.all()) {
  const po = item.json.data || {};
  const articles = Array.isArray(po.articles) ? po.articles : [];

  // --- per-document flagging ---
  const missingHeader = [];
  const headerChecks = {
    'Mark For': po.mark_for,
    'PO Number': po.po_number,
    'PO Date': po.po_date,
    'Delivery Date': po.delivery_date,
    'PR Number': po.pr_number,
    // Reference No. excluded on purpose - blank on most POs
  };
  for (const [label, val] of Object.entries(headerChecks)) {
    if (isMissing(val)) missingHeader.push(label);
  }

  const badArticles = [];
  if (articles.length === 0) {
    badArticles.push('no articles extracted');
  } else {
    articles.forEach((a, i) => {
      const miss = [];
      if (isMissing(a.article)) miss.push('name');
      if (isMissing(a.unit)) miss.push('unit');
      if (isMissing(a.quantity)) miss.push('quantity');
      if (miss.length) badArticles.push(`row ${i + 1} (${miss.join(', ')})`);
    });
  }

  if (missingHeader.length || badArticles.length) {
    sd.flags.push({ document: fileName, missingHeader, badArticles });
  }

  // --- build sheet rows ---
  for (const a of articles) {
    rows.push({
      json: {
        'Document Name': fileName,
        'PO Number': clean(po.po_number),
        'PO Date': clean(po.po_date),
        'Delivery Date': clean(po.delivery_date),
        'Mark For': clean(po.mark_for),
        'PR Number': clean(po.pr_number),
        'Reference No.': clean(po.reference_no),
        'Article': clean(a.article),
        'Unit': clean(a.unit),
        'Quantity': clean(a.quantity),
      },
    });
  }
}

return rows;

const sd = $getWorkflowStaticData('global');
sd.flags = [];

const out = [];

for (const item of $input.all()) {
  const bin = item.binary || {};
  for (const key of Object.keys(bin)) {
    out.push({
      json: { fileName: bin[key].fileName || key },
      binary: { data: bin[key] },
    });
  }
}

return out;

const sd = $getWorkflowStaticData('global');
const flags = Array.isArray(sd.flags) ? sd.flags : [];

let message;
if (flags.length === 0) {
  message = 'All documents were extracted cleanly. No missing fields detected.';
} else {
  const parts = flags.map((f) => {
    const lines = [];
    if (f.missingHeader.length) {
      lines.push(`Missing header fields: ${f.missingHeader.join(', ')}`);
    }
    if (f.badArticles.length) {
      lines.push(`Article issues: ${f.badArticles.join('; ')}`);
    }
    return `• ${f.document}\n   ${lines.join('\n   ')}`;
  });
  message =
    'Some documents may not have extracted fully. Please review the flagged items below and check the original PDFs:\n\n' +
    parts.join('\n\n');
}

return [{ json: { summaryText: message } }];
